/* Convert an HkiManifest into the shape sample-engine consumes from INSTRUMENTS.
   The synthesized object has the same surface as a static entry, with:
     - source: 'hki' marker (sample-engine branches on this to load from
       IndexedDB instead of fetching baseUrl)
     - no baseUrl / ext / filePattern (each sample carries its archive-relative
       `file` field, matching how multi-pattern CDN entries already work)
   The same per-sample fields (segments, trend, trimStart, gain, file) flow
   through unchanged, so the engine's overlay logic doesn't need to know
   whether an instrument is imported or static. */
function manifestToInstrument(m: HkiManifest): any {
  const entry: any = {
    name: m.name,
    source: 'hki',
    baseUrl: '',
    ext: '',
    releaseTime: m.releaseTime,
    volume: m.volume,
    loop: m.loop,
    decays: m.decays,
    samples: m.samples,
  };
  if (m.transpose) entry.transpose = m.transpose;
  if (m.replayOnTranspose) entry.replayOnTranspose = true;
  if (m.vibrato) entry.vibrato = true;
  return entry;
}

/* Lazy synthesis cache. We don't want to rebuild the entry object on every
   `INSTRUMENTS[key]` access (the engine reads through it on every note-on),
   but we DO want it to reflect a re-imported manifest. Keyed by manifest
   reference identity from the registry — when removeBundle/importBundle
   replace the cached record, the manifest reference changes and we re-synth. */
const importedCache = new WeakMap<HkiManifest, any>();
function getImportedEntry(key: string): any | undefined {
  const m = getImportedManifest(key);
  if (!m) return undefined;
  let entry = importedCache.get(m);
  if (!entry) { entry = manifestToInstrument(m); importedCache.set(m, entry); }
  return entry;
}

/* Read-transparent proxy: every consumer that did `INSTRUMENTS[key]` keeps
   working with zero change, and imported instruments are reachable through
   the same surface. */
export const INSTRUMENTS: Record<string, any> = new Proxy(STATIC_INSTRUMENTS, {
  get(target, prop, _receiver) {
    if (typeof prop !== 'string') return Reflect.get(target, prop);
    if (prop in target) return target[prop];
    return getImportedEntry(prop);
  },
  has(target, prop) {
    if (typeof prop !== 'string') return Reflect.has(target, prop);
    return (prop in target) || hasImported(prop);
  },
});
